{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:00Z", "category": "overview", "component_name": "PatternFly 6", "description": "PatternFly 6 is Red Hat's open source design system for enterprise applications. Current version is 6.4.0 with 92 components. Q2 2025 release includes React 19 support across all components and extensions.", "usage_example": "npm install @patternfly/react-core --save", "source_url": "https://www.patternfly.org/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:01Z", "category": "overview", "component_name": "React 19 Support", "description": "PatternFly 6 now includes full React 19 support as of Q2 2025. This is non-breaking and maintains backward compatibility with React 17 and 18. PatternFly supports 2 most recent React versions at a time.", "usage_example": "Works with React 19 out of the box - no special configuration needed", "source_url": "https://www.patternfly.org/get-started/release-highlights/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:02Z", "category": "layout", "component_name": "Page", "description": "Page component defines basic layout with vertical or horizontal navigation. Contains PageGroup, PageBreadcrumb, PageSection, PageSidebar. Supports width-limited sections with isWidthLimited and isCenterAligned props. isContentFilled controls space filling.", "usage_example": "<Page><PageSidebar isSidebarOpen={true}><PageSidebarBody>nav here</PageSidebarBody></PageSidebar><PageSection>content</PageSection></Page>", "source_url": "https://www.patternfly.org/components/page/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:03Z", "category": "layout", "component_name": "PageSidebar", "description": "Vertical sidebar passed to Page via sidebar property. Contains PageSidebarBody for navigation. isSidebarOpen controls visibility. Multiple PageSidebarBody components can be used. usePageInsets modifies component insets, isFilled controls vertical space.", "usage_example": "<PageSidebar isSidebarOpen={isSidebarOpen}><PageSidebarBody><Navigation/></PageSidebarBody></PageSidebar>", "source_url": "https://www.patternfly.org/components/page/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:04Z", "category": "layout", "component_name": "PageSection", "description": "Content section within Page. Supports padding property with breakpoint values (default, sm, md, lg, xl, 2xl) set to 'padding' or 'noPadding'. isWidthLimited reduces section width. Uses --pf-v6-c-page--section--m-limit-width--MaxWidth CSS variable.", "usage_example": "<PageSection padding={{default: 'padding', md: 'noPadding'}}>content</PageSection>", "source_url": "https://www.patternfly.org/components/page/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:05Z", "category": "layout", "component_name": "Masthead", "description": "Contains global properties like logo, navigation, settings. Must contain MastheadMain and MastheadContent. MastheadMain wraps PageToggleButton and MastheadBrand. MastheadBrand wraps MastheadLogo. Header toolbar goes in MastheadContent.", "usage_example": "<Masthead><MastheadMain><MastheadBrand><MastheadLogo>Logo</MastheadLogo></MastheadBrand></MastheadMain><MastheadContent><Toolbar/></MastheadContent></Masthead>", "source_url": "https://www.patternfly.org/components/masthead/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:06Z", "category": "layout", "component_name": "Navigation", "description": "Vertical navigation displays options top to bottom on left side. Horizontal navigation displays items left to right in masthead. For horizontal nav, add navigation inside ToolbarItem in Toolbar passed to MastheadContent.", "usage_example": "<Navigation aria-label='Main'><NavItem>Dashboard</NavItem><NavItem>Tasks</NavItem></Navigation>", "source_url": "https://www.patternfly.org/components/navigation/design-guidelines/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:07Z", "category": "layout", "component_name": "Toolbar", "description": "Responsive container for controls to manage data sets. Supports inset property at breakpoints (insetNone to inset2xl). Items spaced 16px by default, modifiable via gap/columnGap/rowGap. colorVariant changes background. Supports sticky toolbar and multiple rows.", "usage_example": "<Toolbar><ToolbarContent><ToolbarItem><Button>Filter</Button></ToolbarItem></ToolbarContent></Toolbar>", "source_url": "https://www.patternfly.org/components/toolbar/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:08Z", "category": "layout", "component_name": "ToolbarFilter", "description": "Component for filter controls within Toolbar. Expects applied filters and deleteLabelGroup handler. Pass deleteLabelGroup to close entire label group. customLabelGroupContent removes default clear all button.", "usage_example": "<ToolbarFilter chips={filters} deleteChip={onDelete} categoryName='Status'><Select/></ToolbarFilter>", "source_url": "https://www.patternfly.org/components/toolbar/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:09Z", "category": "layout", "component_name": "Tabs", "description": "Contains multiple Tab components for navigation between content sets. TabTitleText for text labels. isDisabled disables tabs. Supports expandable tabs, overflow handling with isOverflowHorizontal, mountOnEnter/unmountOnExit for performance, closeable and addable tabs.", "usage_example": "<Tabs activeKey={activeTab} onSelect={(e, k) => setActiveTab(k)}><Tab eventKey={0} title={<TabTitleText>Overview</TabTitleText>}><TabContent/></Tab></Tabs>", "source_url": "https://www.patternfly.org/components/tabs/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:10Z", "category": "layout", "component_name": "Panel", "description": "Customizable container for flexible content layouts. Separate from Tabs component in PatternFly 6.", "usage_example": "<Panel><PanelMain><PanelMainBody>content</PanelMainBody></PanelMain></Panel>", "source_url": "https://www.patternfly.org/components/panel/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:11Z", "category": "data", "component_name": "Card", "description": "Content container for entry-level information in dashboards, galleries, catalogs. Contains CardTitle, CardBody, CardFooter. Variant='secondary' for secondary styling. Supports expandable cards with CardExpandableContent. Can be used as selectable tiles (tile component deprecated).", "usage_example": "<Card><CardTitle>Task Details</CardTitle><CardBody>Description here</CardBody><CardFooter>Actions</CardFooter></Card>", "source_url": "https://www.patternfly.org/components/card/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:12Z", "category": "data", "component_name": "Card - Selectable", "description": "Cards can replace deprecated tiles. Pass selectableActions object to CardHeader with variant='single' for single-select or default for multi-select. isHidden hides checkbox/radio. isSelected indicates selection state.", "usage_example": "<Card isSelectable><CardHeader selectableActions={{variant: 'single', isSelected: selected, selectableActionId: 'id1'}}><CardTitle>Option 1</CardTitle></CardHeader></Card>", "source_url": "https://www.patternfly.org/components/card/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:13Z", "category": "data", "component_name": "Table", "description": "From @patternfly/react-table package. Composable structure with Thead, Tbody, Tr, Th, Td. Supports selectable rows, expandable rows with isExpandable and ExpandableRowContent, editable rows, actions column with ActionsColumn. dataLabel prop for mobile responsiveness.", "usage_example": "<Table><Thead><Tr><Th>Name</Th><Th>Status</Th></Tr></Thead><Tbody><Tr><Td dataLabel='Name'>Task 1</Td><Td dataLabel='Status'>Active</Td></Tr></Tbody></Table>", "source_url": "https://www.patternfly.org/components/table/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:14Z", "category": "data", "component_name": "Badge", "description": "Annotation displaying numeric value. Used in chip components and menu toggles to show selection count. --pf-v6-c-chip__c-badge--MarginLeft for chip badge margin.", "usage_example": "<Badge>5</Badge>", "source_url": "https://www.patternfly.org/components/badge/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:15Z", "category": "data", "component_name": "Label", "description": "Descriptive annotation adding context. Variants: filled, outlined, compact. Status label combines color and icon. Supports dismissible labels with close icon. Can include custom icons for identification.", "usage_example": "<Label color='blue' icon={<InfoIcon/>}>Information</Label>", "source_url": "https://www.patternfly.org/components/label/design-guidelines/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:16Z", "category": "data", "component_name": "Icon", "description": "Container for icons of varying dimensions and styles. Supports status variants for visual indication. Color-coded status icons should not be used without text label. Never swap status colors between icons.", "usage_example": "<Icon status='danger'><ExclamationCircleIcon/></Icon>", "source_url": "https://www.patternfly.org/components/icon/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:17Z", "category": "data", "component_name": "EmptyState", "description": "Used when no data available or to communicate completion/status at end of tasks. May include call to action. Flexible pattern for various needs. Can show loading screens without data.", "usage_example": "<EmptyState><EmptyStateHeader titleText='No tasks' icon={<EmptyStateIcon icon={SearchIcon}/>}/><EmptyStateBody>Create your first task</EmptyStateBody><EmptyStateFooter><Button>Add Task</Button></EmptyStateFooter></EmptyState>", "source_url": "https://www.patternfly.org/components/empty-state/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:18Z", "category": "data", "component_name": "Progress", "description": "Keeps users informed about effort/time for long processes. Use for processes over 4 seconds. Use determinate progress bar with measurable values. Never combine with spinner. Use toast alert with progress bar for file downloads.", "usage_example": "<Progress value={33} title='Loading' measureLocation='outside'/>", "source_url": "https://www.patternfly.org/components/progress/design-guidelines/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:19Z", "category": "data", "component_name": "Spinner", "description": "Loading indicator positioned center of loading element. Use for 1-5 second waits. For experiences over 5 seconds, use progress bar instead. Use white/light background for contrast.", "usage_example": "<Spinner aria-label='Loading content'/>", "source_url": "https://www.patternfly.org/components/spinner/design-guidelines/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:20Z", "category": "form", "component_name": "Dropdown", "description": "Uses MenuToggle with DropdownList and DropdownItem. isOpen with onOpenChange for state. isDisabled disables items. onClick for callbacks. Plain MenuToggle for kebab icon. DropdownGroup for related items.", "usage_example": "<Dropdown isOpen={isOpen} onOpenChange={setIsOpen} toggle={(toggleRef) => <MenuToggle ref={toggleRef} onClick={() => setIsOpen(!isOpen)}>Actions</MenuToggle>}><DropdownList><DropdownItem>Edit</DropdownItem><DropdownItem>Delete</DropdownItem></DropdownList></Dropdown>", "source_url": "https://www.patternfly.org/components/menus/dropdown/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:21Z", "category": "form", "component_name": "Select", "description": "Menu for selecting 1 or more items. Single select for one item. Checkbox select with role='menu' and hasCheckbox. isSelected for selection state. Badge shows selection count. Typeahead variant with variant='typeahead' on MenuToggle.", "usage_example": "<Select isOpen={isOpen} selected={selected} onSelect={(e, value) => setSelected(value)} toggle={(toggleRef) => <MenuToggle ref={toggleRef}>{selected || 'Select'}</MenuToggle>}><SelectList><SelectOption value='opt1'>Option 1</SelectOption></SelectList></Select>", "source_url": "https://www.patternfly.org/components/menus/select/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:22Z", "category": "form", "component_name": "Menu", "description": "Contains MenuItem components with itemId for callbacks. onSelect logs selection. hasCheck adds checkboxes. MenuFooter for actions at bottom. MenuGroup organizes content with label and labelHeadingLevel props.", "usage_example": "<Menu onSelect={onSelect}><MenuContent><MenuList><MenuItem itemId='item1'>Item 1</MenuItem></MenuList></MenuContent></Menu>", "source_url": "https://www.patternfly.org/components/menus/menu/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:23Z", "category": "form", "component_name": "MenuToggle", "description": "Pairs with Menu or Panel for custom dropdowns/selects. Enables custom configurations not in standard dropdown/select. Can be styled as plain for kebab icons.", "usage_example": "<MenuToggle variant='plain' aria-label='Actions'><EllipsisVIcon/></MenuToggle>", "source_url": "https://www.patternfly.org/components/menus/menu-toggle/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:24Z", "category": "form", "component_name": "TextInput", "description": "For short free-form text. validated prop indicates state: success, warning, error. Modify input to show validation state visually.", "usage_example": "<TextInput value={value} onChange={(e, val) => setValue(val)} validated='success'/>", "source_url": "https://www.patternfly.org/components/forms/text-input/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:25Z", "category": "form", "component_name": "TextInputGroup", "description": "Enhanced text input with icon support via TextInputGroupMain and utilities via TextInputGroupUtilities (like clear button). validated prop with success/warning/error states.", "usage_example": "<TextInputGroup><TextInputGroupMain icon={<SearchIcon/>} value={value} onChange={(e, val) => setValue(val)}/><TextInputGroupUtilities><Button variant='plain' onClick={onClear}><TimesIcon/></Button></TextInputGroupUtilities></TextInputGroup>", "source_url": "https://www.patternfly.org/components/text-input-group/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:26Z", "category": "form", "component_name": "Checkbox", "description": "For selecting all/some/none from up to 5 options. Labels on right of control. Align left edge with other form controls. Supports progressive disclosure with nested controls. Unlike switch, requires separate submit action.", "usage_example": "<Checkbox id='check1' label='Enable feature' isChecked={checked} onChange={(e, val) => setChecked(val)}/>", "source_url": "https://www.patternfly.org/components/forms/checkbox/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:27Z", "category": "form", "component_name": "DatePicker", "description": "Bound-entry control for date input. Constrains user input to valid dates. Combines keyboard and mouse interaction. No field validation needed due to constrained input.", "usage_example": "<DatePicker value={date} onChange={(e, val) => setDate(val)}/>", "source_url": "https://www.patternfly.org/components/date-and-time/date-picker/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:28Z", "category": "form", "component_name": "Form", "description": "Container for form fields. Use top-aligned labels by default, left-aligned for limited vertical space. 24px spacing under each input. Helper text included before spacing calculation.", "usage_example": "<Form><FormGroup label='Name' isRequired><TextInput/></FormGroup></Form>", "source_url": "https://www.patternfly.org/components/forms/form/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:29Z", "category": "form", "component_name": "Button", "description": "Basic interactive element. pf-v6-c-button class for styling, pf-m-primary for primary blue style. Various variants available.", "usage_example": "<Button variant='primary'>Submit</Button>", "source_url": "https://www.patternfly.org/components/button/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:30Z", "category": "theme", "component_name": "Dark Theme", "description": "Ships with PatternFly CSS by default. Enable with pf-v6-theme-dark class on <html> tag. Can toggle dynamically. Supports browser prefers-color-scheme media query. Tokens automatically adapt between themes.", "usage_example": "document.documentElement.classList.add('pf-v6-theme-dark')", "source_url": "https://www.patternfly.org/developer-resources/dark-theme-handbook/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:31Z", "category": "theme", "component_name": "Dark Theme Accessibility", "description": "Light text on dark backgrounds. Color palette adapts to maintain minimum 4.5:1 text contrast ratio and 3:1 non-text contrast ratio. Use PatternFly tokens instead of static color values.", "usage_example": "Use var(--pf-t--global--background--color--primary--default) instead of #fff or white", "source_url": "https://www.patternfly.org/developer-resources/dark-theme-handbook/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:32Z", "category": "theme", "component_name": "Theming", "description": "PatternFly 6 built on new design token system. Tokens cover both light and dark themes. Use tokens for colors, spacing, typography to ensure theme compatibility.", "usage_example": "Use PatternFly components as-is for consistent theme switching", "source_url": "https://www.patternfly.org/design-foundations/theming/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:33Z", "category": "token", "component_name": "Token System Overview", "description": "3 layers: palette tokens (color foundation), base tokens (apply colors to concepts, add spacing/borders), semantic tokens (purpose-specific). CSS variables prefixed with --pf-t--. Formula: --pf-t--global--concept--property--modifier--state", "usage_example": "--pf-t--global--background--color--primary--default", "source_url": "https://www.patternfly.org/tokens/about-tokens/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:34Z", "category": "token", "component_name": "Spacing Tokens", "description": "Start with pft, then sp for spacers, then size (sm, md, lg, xl, 2xl). Use var(--pf-t--global--spacer--sm) format.", "usage_example": "var(--pf-t--global--spacer--sm), var(--pf-t--global--spacer--md), var(--pf-t--global--spacer--lg)", "source_url": "https://www.patternfly.org/tokens/develop-with-tokens/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:35Z", "category": "token", "component_name": "Color Tokens", "description": "Never use hard-coded hex codes. Use semantic tokens like var(--pf-t--global--background--color--disabled--default). Tokens auto-adapt to themes. Never use palette tokens directly (like --pf-t--color--blue--20).", "usage_example": "var(--pf-t--global--background--color--primary--default), var(--pf-t--global--text--color--regular)", "source_url": "https://www.patternfly.org/tokens/develop-with-tokens/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:36Z", "category": "token", "component_name": "React Tokens", "description": "Import from @patternfly/react-tokens. Name format replaces -- with _ and --pf-t prefix becomes t. Example: --pf-t--global--spacer--sm becomes t_global_spacer_sm", "usage_example": "import t_global_spacer_sm from '@patternfly/react-tokens/dist/esm/t_global_spacer_sm'", "source_url": "https://www.patternfly.org/tokens/develop-with-tokens/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:37Z", "category": "token", "component_name": "Breakpoint Tokens", "description": "PatternFly 6 uses rem units for global breakpoint tokens instead of pixels. Update any pixel-based breakpoint logic to use rem-based tokens.", "usage_example": "Breakpoint values: default, sm, md, lg, xl, 2xl", "source_url": "https://www.patternfly.org/get-started/upgrade/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:38Z", "category": "package", "component_name": "@patternfly/react-core", "description": "Main package containing most React core components. Version 6.4.0 is latest. Each component includes its own CSS.", "usage_example": "npm install @patternfly/react-core@^6 --save", "source_url": "https://www.npmjs.com/package/@patternfly/react-core"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:39Z", "category": "package", "component_name": "@patternfly/react-table", "description": "Separate package for Table component. Composable structure mirroring HTML table.", "usage_example": "npm install @patternfly/react-table@^6 --save", "source_url": "https://www.npmjs.com/package/@patternfly/react-table"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:40Z", "category": "package", "component_name": "@patternfly/react-charts", "description": "PatternFly charting components package.", "usage_example": "npm install @patternfly/react-charts --save", "source_url": "https://www.patternfly.org/get-started/develop/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:41Z", "category": "package", "component_name": "@patternfly/react-code-editor", "description": "PatternFly wrapper for Monaco code editor.", "usage_example": "npm install @patternfly/react-code-editor --save", "source_url": "https://www.patternfly.org/get-started/develop/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:42Z", "category": "package", "component_name": "@patternfly/react-icons", "description": "PatternFly icons as React components.", "usage_example": "import { SearchIcon } from '@patternfly/react-icons'", "source_url": "https://www.patternfly.org/get-started/develop/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:43Z", "category": "package", "component_name": "@patternfly/react-tokens", "description": "Design tokens as importable React modules. Token names use underscore format.", "usage_example": "import t_global_spacer_md from '@patternfly/react-tokens/dist/esm/t_global_spacer_md'", "source_url": "https://www.patternfly.org/tokens/develop-with-tokens/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:44Z", "category": "scheduling-ui", "component_name": "Recommended Components for MMS", "description": "For Metro Maintenance Scheduler: Page+Masthead+PageSidebar for layout, Navigation for menu, Toolbar for filters/actions, Card for task details, Table for task lists, Tabs for view switching, Label/Badge for status, DatePicker for scheduling, Select for filtering, EmptyState for no-data views", "usage_example": "Combine Page layout with Card-based task visualization and Table for detailed views", "source_url": "https://www.patternfly.org/components/all-components/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:45Z", "category": "upgrade", "component_name": "PatternFly 6 Upgrade Notes", "description": "New design token system changes all CSS variable names. Existing CSS overrides must be updated or removed. ToolbarItem variants bulk-select, overflow-menu, search-filter removed. Tile component deprecated in favor of Card.", "usage_example": "Review upgrade guide at patternfly.org/get-started/upgrade/", "source_url": "https://www.patternfly.org/get-started/upgrade/"}
{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:46Z", "category": "css", "component_name": "Base CSS Import", "description": "Import PatternFly base CSS for consistent styling across application.", "usage_example": "import '@patternfly/react-core/dist/styles/base.css'", "source_url": "https://www.patternfly.org/get-started/develop/"}

