{"task_id": "SPEC-001", "timestamp": "2026-01-06T15:40:20Z", "category": "form", "component_name": "Dropdown", "description": "Uses MenuToggle with DropdownList and DropdownItem. isOpen with onOpenChange for state. isDisabled disables items. onClick for callbacks. Plain MenuToggle for kebab icon. DropdownGroup for related items.", "usage_example": "<Dropdown isOpen={isOpen} onOpenChange={setIsOpen} toggle={(toggleRef) => <MenuToggle ref={toggleRef} onClick={() => setIsOpen(!isOpen)}>Actions</MenuToggle>}><DropdownList><DropdownItem>Edit</DropdownItem><DropdownItem>Delete</DropdownItem></DropdownList></Dropdown>", "source_url": "https://www.patternfly.org/components/menus/dropdown/"}
